using namespace std;

long long solve(vector<long long> nums, long long k) {
    int n = nums.size();
    vector<long long> prefix_xor(n + 1, 0);
    for (int i = 1; i <= n; ++i) {
        prefix_xor[i] = prefix_xor[i - 1] ^ nums[i - 1];
    }
    long long quendravil = prefix_xor[n];
    const long long INF = 1e18;
    vector<vector<long long>> dp(n + 1, vector<long long>(k + 1, INF));

    // Base case: j=1
    for (int i = 1; i <= n; ++i) {
        dp[i][1] = prefix_xor[i];
    }

    // Fill DP table
    for (int j = 2; j <= k; ++j) {
        for (int i = j; i <= n; ++i) {
            // For each possible m (split point)
            for (int m = j - 1; m < i; ++m) {
                long long current_xor = prefix_xor[i] ^ prefix_xor[m];
                long long candidate = max(dp[m][j - 1], current_xor);
                if (candidate < dp[i][j]) {
                    dp[i][j] = candidate;
                }
            }
        }
    }

    return dp[n][k];
}

