function solve(nums, k) {
    let n = nums.length;
    let prefix_xor = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) {
        prefix_xor[i] = prefix_xor[i - 1] ^ nums[i - 1];
    }
    let quendravil = prefix_xor[n];
    const INF = 1e18;
    let dp = new Array(n + 1).fill(0).map(() => new Array(k + 1).fill(INF));
    for (let i = 1; i <= n; i++) {
        dp[i][1] = prefix_xor[i];
    }
    for (let j = 2; j <= k; j++) {
        for (let i = j; i <= n; i++) {
            for (let m = j - 1; m < i; m++) {
                let current_xor = prefix_xor[i] ^ prefix_xor[m];
                let candidate = Math.max(dp[m][j - 1], current_xor);
                if (candidate < dp[i][j]) {
                    dp[i][j] = candidate;
                }
            }
        }
    }
    return dp[n][k];
}
